7→  const [editId, setEditId] = useState(null);
8→  const [form, setForm] = useState({ username: '', password: '', full_name: '', role: 'MASTER' });
9→  const [error, setError] = useState('');
10→
11→  const token = localStorage.getItem('token');
12→  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
13→  const API = `http://${window.location.hostname}:8000`;
14→
15→  const roleColors = { ADMIN: '#ef4444', MASTER: '#3b82f6', NAZORATCHI: '#22c55e', MECHANIC: '#f59e0b' };
16→
17→  const fetchUsers = async () => {
18→    try {
19→      const res = await fetch(`${API}/users`, { headers });
20→      if (res.ok) setUsers(await res.json());
21→    } catch (e) {}
22→  };
23→
24→  useEffect(() => { fetchUsers(); }, []);
25→
26→  const resetForm = () => {
27→    setForm({ username: '', password: '', full_name: '', role: 'MASTER' });
28→    setShowForm(false);
29→    setEditId(null);
30→    setError('');
31→  };
32→
33→  const handleCreate = async () => {
34→    if (!form.username || !form.password || !form.full_name) {
35→      setError('Barcha maydonlarni toldiring');
36→      return;
37→    }
38→    try {
39→      const res = await fetch(`${API}/users`, {
40→        method: 'POST', headers, body: JSON.stringify(form)
41→      });
42→      if (res.ok) {
43→        fetchUsers();
44→        resetForm();
45→      } else {
46→        const data = await res.json();
47→        setError(data.detail || 'Xatolik');
48→      }
49→    } catch (e) { setError('Server xatoligi'); }
50→  };
51→
52→  const handleUpdate = async () => {
53→    const body = { full_name: form.full_name, role: form.role };
54→    if (form.password) body.password = form.password;
55→    try {
56→      const res = await fetch(`${API}/users/${editId}`, {
57→        method: 'PUT', headers, body: JSON.stringify(body)
58→      });
59→      if (res.ok) {
60→        fetchUsers();
61→        resetForm();
62→      }
63→    } catch (e) { setError('Server xatoligi'); }
64→  };
65→
66→  const handleDelete = async (id) => {
67→    if (!confirm('Rostdan ham ochirmoqchimisiz?')) return;
68→    try {
69→      await fetch(`${API}/users/${id}`, { method: 'DELETE', headers });
70→      fetchUsers();
71→    } catch (e) {}
72→  };
73→
74→  const startEdit = (u) => {
75→    setEditId(u.id);
76→    setForm({ username: u.username, password: '', full_name: u.full_name, role: u.role });
77→    setShowForm(true);
78→    setError('');
79→  };
80→
81→  return (
82→    <div style={{ padding: '1.5rem' }}>
83→      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
84→        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>Foydalanuvchilar Boshqaruvi</h2>
85→        <button onClick={() => { resetForm(); setShowForm(true); }} style={{
86→          display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
87→          background: 'var(--primary)', color: '#0f172a', border: 'none', borderRadius: '10px',
88→          cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
89→        }}>
90→          <Plus size={16} /> Yangi Foydalanuvchi
91→        </button>
92→      </div>
93→
94→      {showForm && (
95→        <div style={{
96→          background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px',
97→          padding: '1.5rem', marginBottom: '1.5rem'
98→        }}>
99→          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>
100→            {editId ? 'Foydalanuvchini Tahrirlash' : 'Yangi Foydalanuvchi'}
101→          </h3>
102→          {error && <p style={{ color: '#ef4444', fontSize: '0.85rem', margin: '0 0 1rem 0' }}>{error}</p>}
103→          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
104→            <div>
105→              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>Username</label>
106→              <input className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
107→                value={form.username} onChange={e => setForm({...form, username: e.target.value})}
108→                disabled={!!editId} placeholder="username" />
109→            </div>
110→            <div>
111→              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>
112→                {editId ? 'Yangi Parol (bosh qoldirish)' : 'Parol'}
113→              </label>
114→              <input className="input-field" type="password" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
115→                value={form.password} onChange={e => setForm({...form, password: e.target.value})}
116→                placeholder="password" />
117→            </div>
118→            <div>
119→              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>To'liq Ism</label>
120→              <input className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
121→                value={form.full_name} onChange={e => setForm({...form, full_name: e.target.value})}
122→                placeholder="Ism Familiya" />
123→            </div>
124→            <div>
125→              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>Rol</label>
126→              <select className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
127→                value={form.role} onChange={e => setForm({...form, role: e.target.value})}>
128→                <option value="MASTER">MASTER</option>
129→                <option value="NAZORATCHI">NAZORATCHI</option>
130→                <option value="MECHANIC">MECHANIC</option>
131→                <option value="ADMIN">ADMIN</option>
132→              </select>
133→            </div>
134→          </div>
135→          <div style={{ display: 'flex', gap: '0.5rem', marginTop: '0.5rem' }}>
136→            <button onClick={editId ? handleUpdate : handleCreate} style={{
137→              display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 20px',
138→              background: 'var(--primary)', color: '#0f172a', border: 'none', borderRadius: '10px',
139→              cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
140→            }}>
141→              <Save size={14} /> {editId ? 'Saqlash' : 'Yaratish'}
142→            </button>
143→            <button onClick={resetForm} style={{
144→              display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 20px',
145→              background: 'rgba(255,255,255,0.05)', color: 'var(--text-muted)', border: '1px solid var(--panel-border)',
146→              borderRadius: '10px', cursor: 'pointer', fontWeight: 600, fontSize: '0.85rem'
147→            }}>
148→              <X size={14} /> Bekor Qilish
149→            </button>
150→          </div>
151→        </div>
152→      )}
153→
154→      <div style={{ background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px', overflow: 'hidden' }}>
155→        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
156→          <thead>
157→            <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
158→              <th style={thStyle}>ID</th>
159→              <th style={thStyle}>Username</th>
160→              <th style={thStyle}>Ism</th>
161→              <th style={thStyle}>Rol</th>
162→              <th style={thStyle}>Holat</th>
163→              <th style={thStyle}>Amallar</th>
164→            </tr>
165→          </thead>
166→          <tbody>
167→            {users.map(u => (
168→              <tr key={u.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
169→                <td style={tdStyle}>{u.id}</td>
170→                <td style={tdStyle}>{u.username}</td>
171→                <td style={tdStyle}>{u.full_name}</td>
172→                <td style={tdStyle}>
173→                  <span style={{
174→                    padding: '3px 10px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: 700,
175→                    background: `${roleColors[u.role] || '#64748b'}22`, color: roleColors[u.role] || '#64748b'
176→                  }}>{u.role}</span>
177→                </td>
178→                <td style={tdStyle}>
179→                  <span style={{ color: u.is_active ? '#22c55e' : '#ef4444', fontSize: '0.8rem' }}>
180→                    {u.is_active ? 'Faol' : 'Nofaol'}
181→                  </span>
182→                </td>
183→                <td style={tdStyle}>
184→                  <div style={{ display: 'flex', gap: '6px' }}>
185→                    <button onClick={() => startEdit(u)} style={actionBtnStyle('#3b82f6')}>
186→                      <Edit2 size={14} />
187→                    </button>
188→                    {u.id !== user.id && (
189→                      <button onClick={() => handleDelete(u.id)} style={actionBtnStyle('#ef4444')}>
190→                        <Trash2 size={14} />
191→                      </button>
192→                    )}
193→                  </div>
194→                </td>
195→              </tr>
196→            ))}
197→          </tbody>
198→        </table>
199→      </div>
200→    </div>
201→  );
202→};
203→
204→const thStyle = {
205→  padding: '12px 16px', textAlign: 'left', fontSize: '0.7rem', fontWeight: 700,
